.scroll-box {
  width: 300px;
  height: 200px;
  overflow: scroll;
}

.scroll-box::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

.scroll-box::-webkit-scrollbar-thumb {
  background-color: #888;
  border-radius: 4px;
}

.scroll-box::-webkit-scrollbar-track {
  background-color: #f0f0f0;
}

.scroll-box {
  width: 300px;
  height: 200px;
  overflow: scroll;
  scrollbar-width: thin;
  scrollbar-color: #888 #f0f0f0;
}
